let ig = {};

try {
  const item = $input.first();
  const d = item.json;
  if (d && !d.error && d.followersCount !== undefined) {
    ig = d;
  }
} catch(e) {
  ig = {};
}

const hasData = Object.keys(ig).length > 0;

// Reference the correct node names from your workflow
let fbData = null;
try { fbData = $('FB Scraper Format1').first().json; } catch(e) {}
try { if (!fbData || !fbData.source) fbData = $('FB Null1').first().json; } catch(e) {}

return [{
  json: {
    source:         "instagram",
    userName:       ig.userName        ?? null,
    followersCount: ig.followersCount  ?? null,
    followsCount:   ig.followsCount    ?? null,
    userUrl:        ig.userUrl         ?? null,
    _ig_available:  hasData,
    _fb_data:       fbData
  }
}];

let fb = {};

try {
  const item = $input.first();
  const d = item.json;
  if (d && !d.error) {
    fb = d;
  }
} catch(e) {
  fb = {};
}

const hasData = !!(fb.followers || fb.likes || fb.email || fb.phone);

return [{
  json: {
    source: "facebook",
    followers:     fb.followers     ?? null,
    likes:         fb.likes         ?? null,
    phone:         fb.phone         ?? null,
    email:         fb.email         ?? null,
    rating:        fb.rating        ?? null,
    ratingOverall: fb.ratingOverall ?? null,
    ratingCount:   fb.ratingCount   ?? null,
    address:       fb.address       ?? null,
    services:      fb.services      ?? null,
    ad_status:     fb.ad_status     ?? null,
    creation_date: fb.creation_date ?? null,
    category:      fb.category      ?? null,
    instagram:     fb.instagram     ?? null,
    _fb_available: hasData
  }
}];

// Code in JavaScript1 — Website Audit Format
let auditData = null;

try {
  const item = $input.first();
  const d = item.json;

  // Parse Result gives us audit_result as an object
  const raw = d.audit_result ?? d;

  if (raw && raw.overall_score !== undefined && raw.overall_score !== null) {
    auditData = {
      overall_score:       raw.overall_score       ?? null,
      design_score:        raw.design_score        ?? null,
      functionality_score: raw.functionality_score ?? null,
      seo_score:           raw.seo_score           ?? null,
      mobile_readiness:    raw.mobile_readiness    ?? null,
      summary:             raw.summary             ?? null,
      top_issues:          raw.top_issues          ?? null,
      recommendation:      raw.recommendation      ?? null
    };
  }
} catch(e) {
  auditData = null;
}

return [{
  json: {
    source: "website_audit",
    audit_result: auditData,
    website_url: (() => {
      try { return $('Test Lead Data').first().json.website_url || null; }
      catch(e) { return null; }
    })(),
    _audit_available: auditData !== null
  }
}];

// IG Null — no instagram found
// Still grab FB data so Merge gets everything
let fbData = null;
try { fbData = $('FB Scraper Format1').first().json; } catch(e) {}
try { if (!fbData || !fbData.source) fbData = $('FB Null1').first().json; } catch(e) {}

return [{
  json: {
    source: "instagram",
    userName:       null,
    followersCount: null,
    followsCount:   null,
    userUrl:        null,
    _ig_available:  false,
    _fb_data:       fbData
  }
}];

// FB Data = Null — no Facebook page exists
return [{
  json: {
    source: "facebook",
    followers: null,
    likes: null,
    phone: null,
    email: null,
    rating: null,
    ratingOverall: null,
    ratingCount: null,
    address: null,
    services: null,
    ad_status: null,
    creation_date: null,
    category: null,
    instagram: null,
    _fb_available: false
  }
}];

// Qualitative Format
let q = {};

try {
  const item = $input.first();
  const d = item.json;

  // Gemini endpoint returns these directly in the response
  // Could be at root level or nested — check both
  if (d) {
    // If your /api/audit/footprint returns fields at root level:
    if (d.vibe_analysis || d.business_name || d.key_offerings) {
      q = d;
    }
    // If it returns an error or non-standard shape, q stays empty
  }
} catch(e) {
  q = {};
}

const hasData = !!(q.vibe_analysis || q.key_offerings);

return [{
  json: {
    source: "qualitative",
    business_name:         q.business_name          ?? null,
    vibe_analysis:         q.vibe_analysis          ?? null,
    key_offerings:         q.key_offerings          ?? null,
    customer_pain_points:  q.customer_pain_points   ?? null,
    digital_presence_gaps: q.digital_presence_gaps  ?? null,
    sentiment_summary:     q.sentiment_summary      ?? null,
    confidence_score:      q.confidence_score       ?? null,
    _qualitative_available: hasData
  }
}];

