const items = $input.all();

let websiteData = { audit_result: null, website_url: null, _audit_available: false };
let igData = { _ig_available: false, _fb_data: null };
let qualData = { _qualitative_available: false };

for (const item of items) {
  const d = item.json;
  if (!d || !d.source) continue;
  if (d.source === "website_audit") websiteData = d;
  if (d.source === "instagram") igData = d;
  if (d.source === "qualitative") qualData = d;
}

const fbData = igData._fb_data || {};
const audit = websiteData.audit_result || {};

let lead = {};
try { lead = $('Test Lead Data').first().json || {}; } catch(e) {}

const out = {
    business_name: lead.business_name ?? qualData.business_name ?? null,
    city: lead.city ?? null,
    facebook_url: lead.facebook_url ?? null,
    website_url: lead.website_url || null,
    place_id: lead.place_id ?? null,

    qualitative: {
      vibe_analysis: qualData.vibe_analysis ?? null,
      key_offerings: qualData.key_offerings ?? null,
      customer_pain_points: qualData.customer_pain_points ?? null,
      digital_presence_gaps: qualData.digital_presence_gaps ?? null,
      sentiment_summary: qualData.sentiment_summary ?? null,
      confidence_score: qualData.confidence_score ?? null
    },

    quantitative: {
      facebook: {
        followers: fbData.followers ?? null,
        likes: fbData.likes ?? null,
        email: fbData.email ?? null,
        phone: fbData.phone ?? null,
        rating: fbData.rating ?? null,
        review_count: fbData.ratingCount ?? null,
        address: fbData.address ?? null,
        services: fbData.services ?? null,
        ad_status: fbData.ad_status ?? null,
        creation_date: fbData.creation_date ?? null,
        category: fbData.category ?? null
      },
      instagram: {
        username: igData.userName ?? null,
        followers: igData.followersCount ?? null,
        follows: igData.followsCount ?? null,
        profile_url: igData.userUrl ?? null
      },
      website: {
        url: websiteData.website_url || null,
        overall_score: audit.overall_score ?? null,
        design_score: audit.design_score ?? null,
        functionality_score: audit.functionality_score ?? null,
        seo_score: audit.seo_score ?? null,
        mobile_readiness: audit.mobile_readiness ?? null,
        summary: audit.summary ?? null,
        top_issues: audit.top_issues ?? null,
        recommendation: audit.recommendation ?? null
      }
    }
};

// This line is the magic fix for "Circular Structure" errors
return [{ json: JSON.parse(JSON.stringify(out)) }];

return [{
  json: {
    source: "website_audit",
    audit_result: null,
    website_url:  $input.first().json.current_lead[0].website ?? null,
    _audit_available: false
  }
}];
